1	export type CellCoordinate = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<CellCoordinate> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const coordKey = (x: number, y: number): string => `${x},${y}`;
10	
11	const survives = (isAlive: boolean, neighborCount: number): boolean =>
12	  neighborCount === 3 || (isAlive && neighborCount === 2);
13	
14	export const nextGeneration = (liveCells: CellCoordinate[]): CellCoordinate[] => {
15	  const liveSet = new Set(liveCells.map(([x, y]) => coordKey(x, y)));
16	  const neighborCounts = new Map<string, { coord: CellCoordinate; count: number }>();
17	
18	  for (const [x, y] of liveCells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const nx = x + dx;
21	      const ny = y + dy;
22	      const k = coordKey(nx, ny);
23	      const existing = neighborCounts.get(k);
24	      if (existing) existing.count += 1;
25	      else neighborCounts.set(k, { coord: [nx, ny], count: 1 });
26	    }
27	  }
28	
29	  const result: CellCoordinate[] = [];
30	  for (const [k, { coord, count }] of neighborCounts) {
31	    if (survives(liveSet.has(k), count)) result.push(coord);
32	  }
33	  return result;
34	};
35

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent live cells (each has 1 neighbor, underpopulation)", () => {
12	    expect(nextGeneration([[0, 0], [1, 0]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) unchanged (each cell has 3 neighbors, survives)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should oscillate a vertical blinker to horizontal", () => {
20	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
21	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
22	    const result = nextGeneration(vertical);
23	    expect(result.sort()).toEqual(horizontal.sort());
24	  });
25	  it("should bring a dead cell to life with exactly 3 neighbors (reproduction)", () => {
26	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
27	    const expected: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
28	    const result = nextGeneration(input);
29	    expect(result.sort()).toEqual(expected.sort());
30	  });
31	  it("should handle negative coordinates correctly", () => {
32	    // Block at negative coords: should be stable
33	    const input: [number, number][] = [[-5, -5], [-4, -5], [-5, -4], [-4, -4]];
34	    const result = nextGeneration(input);
35	    expect(result.sort()).toEqual(input.sort());
36	  });
37	});
